"""
MultiAgentBudgetOptimizer - A collaborative budget management and optimization system
that allows multiple users to manage expenses, set budget limits, and optimize spending.
"""

from __future__ import annotations

import unittest
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple


@dataclass
class Expense:
    """Represents a single expense entry."""
    user_id: str
    category: str
    amount: float
    description: str = ""

    def __post_init__(self):
        if self.amount < 0:
            raise ValueError("Expense amount cannot be negative")
        if not self.category:
            raise ValueError("Category cannot be empty")
        if not self.user_id:
            raise ValueError("User ID cannot be empty")


@dataclass
class UserAccount:
    """Represents a user account with expenses and personal budget tracking."""
    user_id: str
    name: str
    expenses: List[Expense] = field(default_factory=list)

    def add_expense(self, category: str, amount: float, description: str = "") -> Expense:
        expense = Expense(
            user_id=self.user_id,
            category=category,
            amount=amount,
            description=description,
        )
        self.expenses.append(expense)
        return expense

    def total_spent(self) -> float:
        return sum(e.amount for e in self.expenses)

    def spent_by_category(self) -> Dict[str, float]:
        breakdown: Dict[str, float] = {}
        for e in self.expenses:
            breakdown[e.category] = breakdown.get(e.category, 0.0) + e.amount
        return breakdown


@dataclass
class BudgetCategory:
    """Represents a budget limit for a specific category."""
    name: str
    limit: float

    def __post_init__(self):
        if self.limit < 0:
            raise ValueError("Budget limit cannot be negative")


@dataclass
class OptimizationSuggestion:
    """A suggestion for optimizing spending."""
    category: str
    message: str
    potential_savings: float
    priority: str  # "high", "medium", "low"


class MultiAgentBudgetOptimizer:
    """
    Main application class that manages multiple users, budgets, and provides
    collaborative optimization features.
    """

    def __init__(self, group_name: str = "Default Group"):
        self.group_name: str = group_name
        self.users: Dict[str, UserAccount] = {}
        self.budget_categories: Dict[str, BudgetCategory] = {}
        self.total_budget: float = 0.0

    # --- User Management ---

    def add_user(self, user_id: str, name: str) -> UserAccount:
        if not user_id or not name:
            raise ValueError("User ID and name cannot be empty")
        if user_id in self.users:
            raise ValueError(f"User '{user_id}' already exists")
        account = UserAccount(user_id=user_id, name=name)
        self.users[user_id] = account
        return account

    def remove_user(self, user_id: str) -> None:
        if user_id not in self.users:
            raise KeyError(f"User '{user_id}' not found")
        del self.users[user_id]

    def get_user(self, user_id: str) -> UserAccount:
        if user_id not in self.users:
            raise KeyError(f"User '{user_id}' not found")
        return self.users[user_id]

    # --- Expense Management ---

    def add_expense(
        self, user_id: str, category: str, amount: float, description: str = ""
    ) -> Expense:
        user = self.get_user(user_id)
        if category not in self.budget_categories:
            raise ValueError(
                f"Category '{category}' does not exist. "
                "Add it with set_budget_limit first."
            )
        return user.add_expense(category, amount, description)

    # --- Budget Management ---

    def set_total_budget(self, amount: float) -> None:
        if amount < 0:
            raise ValueError("Total budget cannot be negative")
        self.total_budget = amount

    def set_budget_limit(self, category: str, limit: float) -> BudgetCategory:
        if not category:
            raise ValueError("Category name cannot be empty")
        budget = BudgetCategory(name=category, limit=limit)
        self.budget_categories[category] = budget
        return budget

    def adjust_budget_limit(self, category: str, new_limit: float) -> BudgetCategory:
        if category not in self.budget_categories:
            raise KeyError(f"Category '{category}' not found")
        if new_limit < 0:
            raise ValueError("Budget limit cannot be negative")
        self.budget_categories[category].limit = new_limit
        return self.budget_categories[category]

    def remove_budget_category(self, category: str) -> None:
        if category not in self.budget_categories:
            raise KeyError(f"Category '{category}' not found")
        del self.budget_categories[category]

    # --- Dashboard & Reporting ---

    def get_group_total_expenses(self) -> float:
        return sum(user.total_spent() for user in self.users.values())

    def get_remaining_budget(self) -> float:
        return self.total_budget - self.get_group_total_expenses()

    def get_category_spending(self) -> Dict[str, float]:
        spending: Dict[str, float] = {}
        for user in self.users.values():
            for expense in user.expenses:
                spending[expense.category] = (
                    spending.get(expense.category, 0.0) + expense.amount
                )
        return spending

    def get_category_remaining(self) -> Dict[str, float]:
        spending = self.get_category_spending()
        remaining: Dict[str, float] = {}
        for cat_name, budget in self.budget_categories.items():
            remaining[cat_name] = budget.limit - spending.get(cat_name, 0.0)
        return remaining

    def get_individual_contributions(self) -> Dict[str, float]:
        return {uid: user.total_spent() for uid, user in self.users.items()}

    def get_dashboard(self) -> Dict:
        total_expenses = self.get_group_total_expenses()
        remaining = self.get_remaining_budget()
        contributions = self.get_individual_contributions()
        category_spending = self.get_category_spending()
        category_remaining = self.get_category_remaining()
        over_budget_categories = [
            cat for cat, rem in category_remaining.items() if rem < 0
        ]

        return {
            "group_name": self.group_name,
            "total_budget": self.total_budget,
            "total_expenses": total_expenses,
            "remaining_budget": remaining,
            "is_over_budget": remaining < 0,
            "individual_contributions": contributions,
            "category_spending": category_spending,
            "category_remaining": category_remaining,
            "over_budget_categories": over_budget_categories,
            "user_count": len(self.users),
        }

    # --- Collaborative Optimization ---

    def get_optimization_suggestions(self) -> List[OptimizationSuggestion]:
        suggestions: List[OptimizationSuggestion] = []
        category_spending = self.get_category_spending()
        category_remaining = self.get_category_remaining()

        # Check for over-budget categories
        for cat, remaining in category_remaining.items():
            if remaining < 0:
                overage = abs(remaining)
                suggestions.append(
                    OptimizationSuggestion(
                        category=cat,
                        message=(
                            f"Category '{cat}' is over budget by ${overage:.2f}. "
                            f"Consider reducing spending or reallocating from "
                            f"under-utilized categories."
                        ),
                        potential_savings=overage,
                        priority="high",
                    )
                )

        # Suggest reallocation from under-utilized categories
        under_utilized = [
            (cat, rem)
            for cat, rem in category_remaining.items()
            if rem > 0 and self.budget_categories[cat].limit > 0
        ]
        over_budget = [
            (cat, abs(rem))
            for cat, rem in category_remaining.items()
            if rem < 0
        ]

        if under_utilized and over_budget:
            total_surplus = sum(r for _, r in under_utilized)
            total_deficit = sum(d for _, d in over_budget)
            reallocation_amount = min(total_surplus, total_deficit)
            suggestions.append(
                OptimizationSuggestion(
                    category="reallocation",
                    message=(
                        f"Reallocate ${reallocation_amount:.2f} from under-utilized "
                        f"categories ({', '.join(c for c, _ in under_utilized)}) "
                        f"to over-budget categories "
                        f"({', '.join(c for c, _ in over_budget)})."
                    ),
                    potential_savings=reallocation_amount,
                    priority="medium",
                )
            )

        # Identify high-spending users for proportional reduction
        if self.users:
            contributions = self.get_individual_contributions()
            avg_spending = (
                sum(contributions.values()) / len(contributions)
                if contributions
                else 0
            )
            for uid, spent in contributions.items():
                if avg_spending > 0 and spent > avg_spending * 1.5:
                    excess = spent - avg_spending
                    suggestions.append(
                        OptimizationSuggestion(
                            category="user_balance",
                            message=(
                                f"User '{self.users[uid].name}' is spending "
                                f"${excess:.2f} more than average. Consider "
                                f"balancing contributions across the group."
                            ),
                            potential_savings=excess,
                            priority="low",
                        )
                    )

        # Check if overall budget is close to limit
        if self.total_budget > 0:
            utilization = self.get_group_total_expenses() / self.total_budget
            if 0.8 <= utilization < 1.0:
                headroom = self.get_remaining_budget()
                suggestions.append(
                    OptimizationSuggestion(
                        category="overall",
                        message=(
                            f"Budget is {utilization * 100:.0f}% utilized. "
                            f"Only ${headroom:.2f} remaining. "
                            f"Review upcoming expected expenses."
                        ),
                        potential_savings=0.0,
                        priority="medium",
                    )
                )
            elif utilization >= 1.0:
                overage = abs(self.get_remaining_budget())
                suggestions.append(
                    OptimizationSuggestion(
                        category="overall",
                        message=(
                            f"Group is over total budget by ${overage:.2f}. "
                            f"Immediate spending reduction needed."
                        ),
                        potential_savings=overage,
                        priority="high",
                    )
                )

        # Sort by priority
        priority_order = {"high": 0, "medium": 1, "low": 2}
        suggestions.sort(key=lambda s: priority_order.get(s.priority, 3))
        return suggestions

    def apply_reallocation(
        self, from_category: str, to_category: str, amount: float
    ) -> Tuple[BudgetCategory, BudgetCategory]:
        if from_category not in self.budget_categories:
            raise KeyError(f"Category '{from_category}' not found")
        if to_category not in self.budget_categories:
            raise KeyError(f"Category '{to_category}' not found")
        if amount < 0:
            raise ValueError("Reallocation amount cannot be negative")

        from_budget = self.budget_categories[from_category]
        to_budget = self.budget_categories[to_category]

        if amount > from_budget.limit:
            raise ValueError(
                f"Cannot reallocate ${amount:.2f} from '{from_category}' "
                f"(limit: ${from_budget.limit:.2f})"
            )

        from_budget.limit -= amount
        to_budget.limit += amount
        return from_budget, to_budget


